import React, { useContext, useState, useEffect } from 'react';
import { detect } from 'detect-browser';

import frenchFlag from '../assets/frenchflag.png';
import britainFlag from '../assets/britainflag.png';
import wheel from '../assets/wheel.png';
import swipe from '../assets/swipe.png';
import { LangCtxt } from '../customHooks/toggleScroll';

const browser = detect();

const SwitchLang = () => {
  const ctx = useContext(LangCtxt);
  if (!ctx) {
    throw new Error('SwitchLang must be used within LangCtxt provider');
  }
  const { lang } = ctx;
  const [device, setDevice] = useState<'mobile' | 'desktop'>('mobile');

  useEffect(() => {
    if (browser?.os) {
      const deviceName = ['iOS', 'Android OS'].includes(browser.os)
        ? 'mobile'
        : 'desktop';
      setDevice(deviceName);
    }
  }, []);

  const flagClass = (isBig: boolean) =>
    isBig
      ? 'h-[30px] w-[30px] transition-[width,height] duration-200 ease-out'
      : 'h-[15px] w-[15px] transition-[width,height] duration-200 ease-out';

  return (
    <div className="absolute right-[30px] top-[20px] flex animate-lang-fade items-center justify-center opacity-0">
      <img
        className={flagClass(lang === 'fr')}
        src={frenchFlag}
        alt="french_flag"
      />
      {device === 'mobile' ? (
        <img className="h-5 w-5" src={swipe} alt="swipe" />
      ) : (
        <img className="h-5 w-5" src={wheel} alt="wheel" />
      )}
      <img
        className={flagClass(lang === 'en')}
        src={britainFlag}
        alt="britain_flag"
      />
    </div>
  );
};

export default SwitchLang;
